// The three brand faces, embedded (DESIGN.md §3 — The Canon Travels Rule).
//
// A render environment has no system fonts to inherit and no stylesheet to
// cascade from, so it must EMBED the canon itself: Oxanium (display — brand
// marks, plate mastheads, and ALL numerals/coordinates/dates), Space Grotesk
// (body — every reading text, title and label), Monaspace Krypton (mono —
// terminal surfaces only: literal commands, code, ASCII terminal output).
//
// Fonts are embedded as base64 data URIs injected via a <style> element.
// The FontFace API (.load() / document.fonts.load(), which is what
// @remotion/fonts' loadFont uses) hangs indefinitely in the swangle software-GL
// render environment — the Promise never settles, blocking the render forever
// via delayRender. Using a CSS @font-face rule instead lets the browser decode
// the embedded bytes lazily; no network fetch, no Promise to block on. Never
// switch this file to loadFont.
//
// Every face carries the ratified metric overrides (DESIGN.md's One Box Rule):
// each is normalised to the SAME 1.25em metric box so a plain align-items:
// center optically centres a coordinate beside a title beside a date. Without
// them the faces disagree and mixed-face lines drift — exactly where nobody can
// inspect it. Do not re-derive these numbers; they are the web's, byte for byte
// (apps/web/src/styles.css).
//
// Subsets, all from the same bytes the web serves (apps/web/public/fonts):
//   Oxanium        latin + latin-ext, weight 200-800   (12.3KB + 7.0KB)
//   Space Grotesk  latin + latin-ext, weight 300-700   (22.3KB + 18.9KB)
//   Monaspace Krypton  latin only, 400 + 700           (19.7KB + 19.6KB)
// Monaspace ships unsubsetted at ~43KB per weight; it is subset to the latin
// range here (fonttools) because base64 inflates the bundle a further ~33%.
//
// Determinism note: the inject is a side effect run at module load, not inside
// a composition, so it does not break frame-determinism.

/** The display family: brand marks, mastheads, and every numeral. */
export const OXANIUM = "Oxanium" as const;

/** Oxanium stack mirroring DESIGN.md's display/numeric roles. */
export const OXANIUM_STACK = "Oxanium, ui-sans-serif, system-ui, sans-serif" as const;

/** The body family: every reading text, title and label. Max weight 700. */
export const SPACE_GROTESK = "Space Grotesk" as const;

/** Space Grotesk stack mirroring DESIGN.md's body/title/label roles. */
export const SPACE_GROTESK_STACK = "Space Grotesk, ui-sans-serif, system-ui, sans-serif" as const;

/** The mono family: terminal surfaces only (literal commands, code, ASCII). */
export const MONASPACE = "Monaspace Krypton" as const;

/** Monaspace stack mirroring DESIGN.md's mono role. */
export const MONO_STACK = "Monaspace Krypton, ui-monospace, SF Mono, Menlo, monospace" as const;

const OXANIUM_LATIN_B64 =
  "";

const OXANIUM_LATIN_EXT_B64 =
  "";

const SPACE_GROTESK_LATIN_B64 =
  "";

const SPACE_GROTESK_LATIN_EXT_B64 =
  "";

const MONASPACE_400_B64 =
  "";

const MONASPACE_700_B64 =
  "";

/** The latin subset's unicode-range, as the web serves it. */
const LATIN_RANGE =
  "U+0000-00FF, U+0131, U+0152-0153, U+02BB-02BC, U+02C6, U+02DA, U+02DC, U+0304, U+0308, U+0329, U+2000-206F, U+20AC, U+2122, U+2191, U+2193, U+2212, U+2215, U+FEFF, U+FFFD";

/** The latin-ext subset's unicode-range, as the web serves it. */
const LATIN_EXT_RANGE =
  "U+0100-02BA, U+02BD-02C5, U+02C7-02CC, U+02CE-02D7, U+02DD-02FF, U+0304, U+0308, U+0329, U+1D00-1DBF, U+1E00-1E9F, U+1EF2-1EFF, U+2020, U+20A0-20AB, U+20AD-20C0, U+2113, U+2C60-2C7F, U+A720-A7FF";

type Face = {
  family: string;
  b64: string;
  /** A variable face takes a range ("200 800"); a static cut takes one number. */
  weight: string;
  /** The One Box Rule overrides, per face. */
  ascent: string;
  descent: string;
  unicodeRange?: string;
};

const FACES: Face[] = [
  // Oxanium — variable, 200-800 (DESIGN.md §3).
  {
    ascent: "97%",
    b64: OXANIUM_LATIN_B64,
    descent: "28%",
    family: OXANIUM,
    unicodeRange: LATIN_RANGE,
    weight: "200 800",
  },
  {
    ascent: "97%",
    b64: OXANIUM_LATIN_EXT_B64,
    descent: "28%",
    family: OXANIUM,
    unicodeRange: LATIN_EXT_RANGE,
    weight: "200 800",
  },
  // Space Grotesk — variable, 300-700. 700 is the axis ceiling: an 800 request
  // clamps silently, so no role may ask for it.
  {
    ascent: "97.5%",
    b64: SPACE_GROTESK_LATIN_B64,
    descent: "27.5%",
    family: SPACE_GROTESK,
    unicodeRange: LATIN_RANGE,
    weight: "300 700",
  },
  {
    ascent: "97.5%",
    b64: SPACE_GROTESK_LATIN_EXT_B64,
    descent: "27.5%",
    family: SPACE_GROTESK,
    unicodeRange: LATIN_EXT_RANGE,
    weight: "300 700",
  },
  // Monaspace Krypton — two static cuts, latin only.
  { ascent: "99%", b64: MONASPACE_400_B64, descent: "26%", family: MONASPACE, weight: "400" },
  { ascent: "99%", b64: MONASPACE_700_B64, descent: "26%", family: MONASPACE, weight: "700" },
];

const faceRule = (face: Face): string =>
  [
    `@font-face {`,
    `  font-family: "${face.family}";`,
    `  font-style: normal;`,
    `  font-weight: ${face.weight};`,
    `  font-display: block;`,
    // The One Box Rule: the same 1.25em metric box for every face, so mixed-face
    // lines (a coordinate beside a title) optically centre on their own.
    `  ascent-override: ${face.ascent};`,
    `  descent-override: ${face.descent};`,
    `  line-gap-override: 0%;`,
    `  src: url("data:font/woff2;base64,${face.b64}") format("woff2");`,
    face.unicodeRange === undefined ? undefined : `  unicode-range: ${face.unicodeRange};`,
    `}`,
  ]
    .filter((line) => line !== undefined)
    .join("\n");

let injected = false;

/**
 * Injects @font-face CSS for all three canon faces. Safe to call many times
 * (idempotent). Browser-only: no-ops in non-DOM contexts (SSR bundling).
 */
export const loadFonts = (): void => {
  if (injected) {
    return;
  }
  if (typeof document === "undefined") {
    return;
  }

  const style = document.createElement("style");
  style.textContent = FACES.map(faceRule).join("\n");
  document.head.appendChild(style);
  injected = true;
};

// Eagerly inject at import so the faces are registered before first paint.
loadFonts();
